"use strict";function toggleCommentEditable(e){e.closest(".js-balloon").querySelector(".js-comment-editable").classList.toggle("hidden"),e.closest(".js-balloon").querySelector(".js-comment-plain").classList.toggle("hidden")}function deleteComment(e){window.confirm("Are you sure you want to delete this comment?")&&fetch(e,{method:"POST",headers:{"X-CSRFToken":csrftoken}}).then(e=>{window.location.reload()})}function submitOnCtrlEnter(e){"Enter"===e.key&&e.ctrlKey&&(e.preventDefault(),e.target.form.submit())}